// ================================================================
// Node: Extract Transaction Data from Jago Email
// Adjust regex patterns to match actual Bank Jago email format
// ================================================================

const item = $input.first();
const subject = item.json.subject || '';
const body    = item.json.text   || item.json.snippet || '';
const html    = item.json.html   || '';
const rawText = html ? html.replace(/<[^>]+>/g, ' ') : body;

// --- Determine transaction type from subject ---
// Adjust keywords to match Jago's actual email subjects
let tipe = 'debit';
if (/masuk|kredit|transfer masuk|top.?up/i.test(subject + rawText)) {
  tipe = 'kredit';
}

// --- Extract Nominal ---
// Pattern: Rp 1.250.000 or Rp1.250.000,00 or IDR 1,250,000
const nominalMatch = rawText.match(
  /(?:Rp\.?\s?|IDR\s?)([\d.,]+)/i
);
let nominal = 0;
if (nominalMatch) {
  // Normalize: remove dots used as thousand sep, replace comma decimal
  nominal = parseFloat(
    nominalMatch[1].replace(/\./g, '').replace(',', '.')
  );
}

// --- Extract Tanggal & Waktu ---
// Pattern: 25 Feb 2025, 10:30 WIB
const dateMatch = rawText.match(
  /(\d{1,2})\s+(Jan(?:uari)?|Feb(?:ruari)?|Mar(?:et)?|Apr(?:il)?|Mei|Jun(?:i)?|Jul(?:i)?|Agt|Agu(?:stus)?|Sep(?:tember)?|Okt(?:ober)?|Nov(?:ember)?|Des(?:ember)?)\s+(\d{4})/i
);
const timeMatch = rawText.match(/(\d{2}:\d{2})(?:\s*WIB)?/i);

const monthMap = {
  jan: '01', januari: '01', feb: '02', februari: '02',
  mar: '03', maret: '03', apr: '04', april: '04',
  mei: '05', jun: '06', juni: '06', jul: '07', juli: '07',
  agt: '08', agu: '08', agustus: '08', sep: '09', september: '09',
  okt: '10', oktober: '10', nov: '11', november: '11',
  des: '12', desember: '12'
};

let tanggalWaktu = new Date().toISOString(); // fallback = now
if (dateMatch) {
  const day = dateMatch[1].padStart(2, '0');
  const mon = monthMap[dateMatch[2].toLowerCase().slice(0, 3)];
  const yr  = dateMatch[3];
  const hr  = timeMatch ? timeMatch[1] : '00:00';
  // WIB = UTC+7
  tanggalWaktu = `${yr}-${mon}-${day}T${hr}:00+07:00`;
}

// --- Extract Merchant / Deskripsi ---
// Common patterns: 'Pembayaran ke MERCHANT_NAME' or 'Transfer ke ...'
const merchantPatterns = [
  /(?:ke|to|merchant|di|at)\s*:?\s*([A-Za-z0-9 &.,'-]{3,50})/i,
  /(?:pembayaran|payment)\s+(?:ke|to)?\s*:?\s*([A-Za-z0-9 &.,'-]{3,50})/i,
];
let merchant = 'Unknown';
for (const pat of merchantPatterns) {
  const m = rawText.match(pat);
  if (m) { merchant = m[1].trim(); break; }
}

// --- Auto-categorize ---
const kategoriMap = [
  { keywords: /makan|resto|food|warung|cafe|kfc|mcd|gopay food|grab food/i, kat: 'Makanan & Minuman' },
  { keywords: /tokopedia|shopee|lazada|blibli|toko/i,                        kat: 'Belanja Online' },
  { keywords: /gojek|grab|ojek|taxi|transjakarta|krl|mrt/i,                  kat: 'Transportasi' },
  { keywords: /pln|listrik|pdam|air|internet|wifi|telkom/i,                  kat: 'Utilitas' },
  { keywords: /netflix|spotify|youtube|disney|steam/i,                        kat: 'Hiburan & Langganan' },
  { keywords: /atm|tunai|cash|tarik/i,                                        kat: 'Tarik Tunai' },
  { keywords: /transfer/i,                                                    kat: 'Transfer' },
];
let kategori = 'Lain-lain';
for (const k of kategoriMap) {
  if (k.keywords.test(merchant + ' ' + rawText)) {
    kategori = k.kat;
    break;
  }
}

// --- Validation ---
if (nominal === 0) {
  throw new Error(`Nominal tidak ditemukan di email: ${subject}`);
}

return [{
  json: {
    tanggal_waktu:      tanggalWaktu,
    tipe,
    nominal,
    merchant_deskripsi: merchant,
    kategori_otomatis:  kategori,
    email_subject:      subject,
    raw_email_body:     rawText.slice(0, 1000), // limit for storage
  }
}];
